// Pull sender name + message text from Evolution webhook payload.
const body = $input.first().json.body ?? $input.first().json;
const data = body.data ?? body;
const key = data.key ?? {};
if (key.fromMe === true) return []; // ignore own messages
const inner = data.message ?? data;
const m = inner.message ?? inner;
function textOf(x) {
  if (!x) return '';
  if (typeof x.conversation === 'string') return x.conversation;
  if (x.extendedTextMessage?.text) return String(x.extendedTextMessage.text);
  if (x.imageMessage?.caption) return String(x.imageMessage.caption);
  if (x.audioMessage) return '[voice note]';
  return '';
}
const msgText = textOf(m).trim();
if (!msgText) return [];
const pushName = data.pushName || inner.pushName || key.remoteJid?.split('@')[0] || 'Someone';
const spokenText = `WhatsApp from ${pushName}: "${msgText.slice(0, 200)}"`;
return [{ json: { spokenText } }];
